// Inline module simulation (everything in one file for the sandbox)
function add(a: number, b: number): number { return a + b; }
function multiply(a: number, b: number): number { return a * b; }
const PI = 3.14159;

// Usage
const sum = add(3, 4);
const product = multiply(3, 4);
const circumference = 2 * PI * 5;

console.log(sum);
console.log(product);
console.log(circumference.toFixed(2));

// Types that would normally be in a separate file
interface ApiResponse<T> {
  data: T;
  status: number;
  message: string;
}

interface User {
  id: number;
  name: string;
}

// Function that uses the types
function createResponse<T>(data: T, status = 200): ApiResponse<T> {
  return { data, status, message: status === 200 ? "OK" : "Error" };
}

const userResponse: ApiResponse<User> = createResponse({ id: 1, name: "Alice" });
console.log(userResponse.status);
console.log(userResponse.data.name);
console.log(userResponse.message);
